module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);

reg [2:0] bit_count;
reg [7:0] shift_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        bit_count <= 0;
        shift_reg <= 0;
        dout_parallel <= 0;
        dout_valid <= 0;
    end else begin
        if (din_valid) begin
            shift_reg <= {shift_reg[6:0], din_serial};
            bit_count <= bit_count + 1;
            if (bit_count == 7) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1;
            end else begin
                dout_valid <= 0;
            end
        end else begin
            dout_valid <= 0;
        end
    end
end

endmodule
